#include "current_acs712.h"
#include <Arduino.h>
#define ACS_PIN 34
#define SENSITIVITY 0.185
static float _current=0,_peak=0;static unsigned long _l=0;
void acs712_setup(){analogReadResolution(12);Serial.println("[acs712] OK");}
void acs712_loop(){if(millis()-_l<100)return;_l=millis();int raw=0;for(int i=0;i<10;i++)raw+=analogRead(ACS_PIN);raw/=10;float v=raw*3.3/4095.0;_current=(v-1.65)/SENSITIVITY;if(abs(_current)>abs(_peak))_peak=_current;}
float acs712_get_current(){return _current;}
float acs712_get_peak(){return _peak;}
